BEGIN TRANSACTION;
INSERT OR REPLACE INTO users (id,email,username,display_username,display_name,email_verified,created_at,updated_at,bio,avatar,favorites) VALUES ('jack-settleman','jack@snapbacksports.com','jacksettleman','JackSettleman','Jack Settleman',1,'2026-07-12T21:14:43.126Z','2026-07-12T21:14:43.126Z',NULL,'data:image/jpeg;base64,',NULL);
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('6b6f3b3a35155c9a623b2922','venue','1830','getting-there','jack-settleman','Jack Settleman','Best ways in: walking, the subway, the LIRR, or NJ Transit. Driving would be my last choice.','2026-07-12T21:14:43.126Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('6a8760f68f5a201982f51bff','venue','1830','before','jack-settleman','Jack Settleman','Pregame spots nearby: Nick and Stef''s Steakhouse, The Rutherford, Stout, Mustang Harry''s, and American Whiskey.','2026-07-12T21:14:43.126Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('4f59c873f908ab1b3e35563d','venue','1830','before','jack-settleman','Jack Settleman','There is a Chase reserve lounge inside the arena. You can reserve a spot pregame.','2026-07-12T21:14:43.126Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('0412f9dd6ed48948cd3c0c2d','venue','1830','best-seats','jack-settleman','Jack Settleman','Front rows in the 200s in the center sections beat behind the basket, even down low.','2026-07-12T21:14:43.126Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d3f5478f0683d1a97c6de2d7','venue','1830','best-seats','jack-settleman','Jack Settleman','The Chase Bridge and the Hyundai Bridge are both cool spots, and the Hyundai Bridge is good value.','2026-07-12T21:14:43.126Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('50dedbb50eadaa228f5bfb9b','venue','1830','best-seats','jack-settleman','Jack Settleman','The Delta Club comes with all-inclusive food and drink (non-alcoholic).','2026-07-12T21:14:43.126Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d61f3925336e43ab94d28049','venue','1830','atmosphere','jack-settleman','Jack Settleman','Best crowd in the NBA. Be ready to stand, and the seats are tight between people. There are not as many gimmicks as other NBA arenas, so it is not the most family-friendly, but there is still plenty of in-game entertainment like t-shirt tosses.','2026-07-12T21:14:43.126Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('414c48d7e2742b0f6b744c24','venue','1830','food','jack-settleman','Jack Settleman','Best food in MSG is the steak sandwich outside section 107.','2026-07-12T21:14:43.126Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('6c7388cb1ff4d8f64ce48709','venue','1830','food','jack-settleman','Jack Settleman','The hamburgers from the Garden Market are the best basic food item in sports. They use a different type of bun that is fantastic.','2026-07-12T21:14:43.126Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('6c8c1deb3458ca99e7522d70','venue','1830','food','jack-settleman','Jack Settleman','Carnegie Deli is another good one. Skip the pizza, it is bad in the arena.','2026-07-12T21:14:43.126Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d7149da45d6152fceb03fe7b','venue','1830','tips','jack-settleman','Jack Settleman','The merch store through the gates on the 100 level has a way shorter line than the one in the MSG lobby.','2026-07-12T21:14:43.126Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('2a39c5ba631d4ff5eaab868a','venue','1830','tips','jack-settleman','Jack Settleman','Alcoholic drinks are very expensive inside MSG.','2026-07-12T21:14:43.126Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('972fa96afcfc43bcb682fde2','venue','1830',NULL,'jack-settleman','Jack Settleman',NULL,'Best crowd in the NBA. Be ready to stand and the seats are tight, but the energy is worth it. For seats, the front rows in the 200s in the center sections beat behind the basket even down low, and the Hyundai Bridge is a cool spot with good value. Eat the steak sandwich outside section 107 and the Garden Market hamburgers, and skip the arena pizza. Get in through the 100 level gates for a shorter merch line, and know the alcohol is very expensive.','2026-07-12T21:14:43.126Z');
COMMIT;
